/*===================================================================================================================================*/
/*  U1    u1_g_oXDoCANDtcTrchk_B1507(const U2 u2_a_ELPSD)                                                                            */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      void                                                                                                             */
/*  Return:         OXDC_DTC_TR_INA  (0x00U)  : DTC INActive                                                                         */
/*                  OXDC_DTC_TR_ACT  (0x01U)  : DTC ACTive                                                                           */
/*                  OXDC_DTC_TR_N_A  (0x02U)  : DTC Not Applicable                                                                   */
/*===================================================================================================================================*/
U1    u1_g_oXDoCANDtcTrchk_B1507(const U2 u2_a_ELPSD)
{
#if (THBLNKR_OSC_OPEN != OXDC_DTC_TR_ACT)
#error "tydocan_met_dtc_B1507.c : THBLNKR_OSC_OPEN shall be equal to OXDC_DTC_TR_ACT."
#endif 
    return(u1_g_ThblnkrDtcTrchk() & (U1)THBLNKR_OSC_OPEN);
}
